var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"부단장님. 소대 편성 및 작전 준비를 끝마쳤습니다.","JPN":"副団長。小隊編成および作戦の準備が終わりました。","ENG":"Deputy, all squads have been organized and mission prep is complete.","TWN":"副團長，已經完成小隊編成及作戰準備。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"부디 명령을 하달해 주시죠.","JPN":"どうかご命令を。","ENG":"We are awaiting your orders.","TWN":"請下達命令吧。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"전 인원, 함선에 탑승 및 권역 감시 상태를 유지해주세요.","JPN":"全員、艦船に搭乗し圏域監視状態を維持してください。","ENG":"Have all units board the ship and maintain regional surveillance.","TWN":"全體人員，請保持登艦及區域監視狀態。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"지체할 이유는 없으니 즉시 현장으로 출발하겠습니다.","JPN":"遅らせる理由はありませんので、ただちに現場に向かいます。","ENG":"There's no reason to delay. We'll depart for the site immediately.","TWN":"沒有理由拖延，我會立即出發前往現場。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"예! 알겠습니다!","JPN":"はい！　かしこまりました！","ENG":"Yes, ma'am!","TWN":"是！明白！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"그런 몸으로 정말 괜찮겠나요, 피오네 경?","JPN":"本当にその体で大丈夫ですか？　フィオネ卿。","ENG":"Are you sure you're up for this in your condition, Dame Fione?","TWN":"這樣的身體真的沒問題嗎，菲奧尼卿？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"걱정하시는 것은 이해하나, 가치판단을 가리지 못할 만큼 판단이 흐려진 것은 아닙니다.","JPN":"ご心配は理解できますが、価値判断ができないほど判断力が低下しているわけではありません。","ENG":"I understand your concern, but my judgment isn't so clouded that I'd ignore reason.","TWN":"我理解你的擔憂，但我的判斷並沒有模糊到無法分辨價值判斷的程度。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"무엇보다 지휘권을 지닌 인원의 작전 편제는 필수적이고요.","JPN":"なにより、指揮権を持っている人員の作戦編制は必須です。","ENG":"Besides, having a commanding officer directly manage the operation is essential.","TWN":"最重要的是，擁有指揮權的人員的作戰編制是必不可少的。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"죄송해요. 저도 힘이 되어드리고 싶지만…….","JPN":"申し訳ありません。私も力になりたいのですが……","ENG":"I'm sorry. I wish I could be of more help...","TWN":"對不起。我也想幫上忙，但是……"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"원로원의 동의 없는 우발적인 행동은 다시금 기사단에 부정적인 결과를 가져올 겁니다.","JPN":"元老院の同意のない突然の行動は、再び騎士団に否定的な結果をもたらすでしょう。","ENG":"Any rash actions without the Council's approval would only harm the Order again.","TWN":"沒有元老院的同意，突發行動將再次給騎士團帶來負面結果。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"메데이아 경이 저희의 뒤를 봐주시는 것은, 무엇보다도 큰 힘이 되죠.","JPN":"メデイア卿が支持してくださるだけで、とても心強いです。","ENG":"Having you watching our backs is more valuable than anything else, Dame Medea.","TWN":"美狄亞在背後支持我們，這比什麼都更有力量。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"레드시프트의 습격에 대비해 본부에도 인원은 남아야 하니, 현재의 구성이 합리적입니다.","JPN":"レッドシフトの襲撃に備えて本部にも残る人員が必要ですので、この構成が合理的です。","ENG":"We still need to leave personnel at HQ in case of another Red Shift attack. This setup is the most practical.","TWN":"為了應對紅移的襲擊，總部也需要留人，所以目前的配置是合理的。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"……어떤 상황에서든, 살아야 그 다음이 있는 법입니다.","JPN":"……どんな状況であっても、まずは生き残らないと次はありません。","ENG":"...No matter the situation, you have to survive if you want to see what comes next.","TWN":"……無論在什麼情況下，只有活著才有未來。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"잊지 마세요, 피오네 경.","JPN":"お忘れなく、フィオネ卿。","ENG":"Don't forget that, Dame Fione.","TWN":"不要忘記，菲奧尼卿。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"예. 명심하겠습니다.","JPN":"はい。承知いたしました。","ENG":"Understood. I won't forget.","TWN":"是！我明白了！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"부단장님. 전 인원, 탑승 완료했습니다!","JPN":"副団長。全員、搭乗完了です！","ENG":"Deputy! All units are aboard!","TWN":"副團長，全員已搭乘完畢！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"메데이아 경. 그럼 저도 이만…….","JPN":"メデイア卿。それでは私も……","ENG":"Then I'll be off, Dame Medea...","TWN":"美狄亞。那我也先行告辭……"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"아, 그전에 잠시 괜찮을까요?","JPN":"あ、その前に少しいいでしょうか？","ENG":"Ah, before you go, could I have a moment with you?","TWN":"啊，在此之前可以打擾一下嗎？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"예?","JPN":"え？","ENG":"Yes?","TWN":"嗯？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"메, 메데이아 경?","JPN":"メ、メデイア卿？","ENG":"D-Dame Medea?","TWN":"美、美狄亞？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"후후. 무사히 다녀오라는 의미의 포옹이에요.","JPN":"ふふ。無事に帰っていらっしゃいのハグです。","ENG":"Haha. Just a hug to wish you a safe return.","TWN":"呵呵。這是祝你平安歸來的擁抱喔。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"LAUGH2"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"제가 이렇게까지 했으니 지면 안 되는 거 알죠?","JPN":"私がここまでしましたから、負けてはいけませんよ？","ENG":"Now that I've done this, you know you can't lose, right?","TWN":"我都做到這個地步了，你知道不能輸吧？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……네. 물론입니다.","JPN":"……はい、もちろんです。","ENG":"...Of course. I won't.","TWN":"……是的。當然。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"다녀오겠습니다, 메데이아 경.","JPN":"行ってきます、メデイア卿。","ENG":"I'll see you when I get back, Dame Medea.","TWN":"那我走了，美狄亞。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"휴우. 들키는 줄 알고 애 떨어지는 줄 알았네.","JPN":"ふう。バレるかと思って緊張したわ。","ENG":"Whew. Thought for sure she was going to catch on.","TWN":"呼，差點被發現，真是嚇死我了。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};